{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyPBIpkVbceLNERIqqASJaTQ"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","source":["Now let me build the full backend and frontend. I'll create files in parallel.\n","Action: file_editor create /app/backend/server.py --file-text \"\\\"\\\"\\\"OmniArena Nexus — AI Stadium Operations Director backend.\\\"\\\"\\\"\n","from fastapi import FastAPI, APIRouter, HTTPException\n","from fastapi.responses import StreamingResponse\n","from dotenv import load_dotenv\n","from starlette.middleware.cors import CORSMiddleware\n","from motor.motor_asyncio import AsyncIOMotorClient\n","import os\n","import json\n","import asyncio\n","import logging\n","import random\n","import uuid\n","from pathlib import Path\n","from typing import List, Optional, Dict, Any, Literal\n","from datetime import datetime, timezone\n","from pydantic import BaseModel, Field, ConfigDict\n","\n","ROOT_DIR = Path(__file__).parent\n","load_dotenv(ROOT_DIR / \\\".env\\\")\n","\n","mongo_url = os.environ[\\\"MONGO_URL\\\"]\n","client = AsyncIOMotorClient(mongo_url)\n","db = client[os.environ[\\\"DB_NAME\\\"]]\n","\n","EMERGENT_LLM_KEY = os.environ.get(\\\"EMERGENT_LLM_KEY\\\", \\\"\\\")\n","\n","app = FastAPI(title=\\\"OmniArena Nexus\\\")\n","api = APIRouter(prefix=\\\"/api\\\")\n","\n","logging.basicConfig(level=logging.INFO)\n","log = logging.getLogger(\\\"nexus\\\")\n","\n","\n","# ---------- Models ----------\n","def now_iso() -> str:\n","    return datetime.now(timezone.utc).isoformat()\n","\n","\n","class MatchConfig(BaseModel):\n","    model_config = ConfigDict(extra=\\\"ignore\\\")\n","    id: str = Field(default_factory=lambda: str(uuid.uuid4()))\n","    stadium: str\n","    home_team: str\n","    away_team: str\n","    kickoff: str\n","    capacity: int = 80000\n","    started_at: str = Field(default_factory=now_iso)\n","    sim_speed: float = 1.0\n","    active_model: str = \\\"openai/gpt-5.2\\\"\n","\n","\n","class CreateMatch(BaseModel):\n","    stadium: str\n","    home_team: str\n","    away_team: str\n","    kickoff: str\n","    capacity: int = 80000\n","    active_model: str = \\\"openai/gpt-5.2\\\"\n","\n","\n","class Telemetry(BaseModel):\n","    match_id: str\n","    ts: str\n","    crowd_movement: int\n","    weather_temp: float\n","    weather_wind: float\n","    weather_condition: str\n","    ticket_validation: int\n","    parking_occupied: int\n","    parking_capacity: int\n","    security_score: int\n","    cctv_alerts: int\n","    medical_active: int\n","    energy_load_kw: int\n","    food_stock_pct: int\n","    transport_delay_min: int\n","    stadium_capacity_pct: int\n","    match_minute: int\n","\n","\n","class TriggerReq(BaseModel):\n","    event_type: Literal[\n","        \\\"crowd_surge\\\",\n","        \\\"medical_emergency\\\",\n","        \\\"weather_alert\\\",\n","        \\\"power_spike\\\",\n","        \\\"security_breach\\\",\n","        \\\"transport_delay\\\",\n","        \\\"food_shortage\\\",\n","        \\\"ticket_fraud\\\",\n","        \\\"cctv_anomaly\\\",\n","    ]\n","    zone: Optional[str] = None\n","    severity: Optional[Literal[\\\"low\\\", \\\"medium\\\", \\\"high\\\", \\\"critical\\\"]] = None\n","\n","\n","class Incident(BaseModel):\n","    model_config = ConfigDict(extra=\\\"ignore\\\")\n","    id: str = Field(default_factory=lambda: str(uuid.uuid4()))\n","    match_id: str\n","    event_type: str\n","    zone: str\n","    severity: str\n","    detected_at: str = Field(default_factory=now_iso)\n","    resolved_at: Optional[str] = None\n","    resolution_seconds: Optional[int] = None\n","    status: str = \\\"open\\\"\n","    context: Dict[str, Any] = {}\n","\n","\n","class DecideReq(BaseModel):\n","    incident_id: str\n","    model: Optional[str] = None  # provider/model\n","\n","\n","class CompareReq(BaseModel):\n","    incident_id: str\n","\n","\n","class SettingsPatch(BaseModel):\n","    sim_speed: Optional[float] = None\n","    active_model: Optional[str] = None\n","\n","\n","# ---------- Simulation State ----------\n","STADIUM_ZONES = [\n","    \\\"north_stand\\\", \\\"south_stand\\\", \\\"east_stand\\\", \\\"west_stand\\\",\n","    \\\"gate_a\\\", \\\"gate_b\\\", \\\"gate_c\\\", \\\"gate_d\\\",\n","    \\\"concourse_north\\\", \\\"concourse_south\\\",\n","    \\\"medical_bay_1\\\", \\\"medical_bay_2\\\",\n","    \\\"parking_lot_a\\\", \\\"parking_lot_b\\\",\n","    \\\"vip_lounge\\\", \\\"pitch\\\",\n","]\n","\n","EVENT_ZONE_MAP = {\n","    \\\"crowd_surge\\\": [\\\"gate_a\\\", \\\"gate_b\\\", \\\"gate_c\\\", \\\"gate_d\\\", \\\"concourse_north\\\", \\\"concourse_south\\\"],\n","    \\\"medical_emergency\\\": [\\\"north_stand\\\", \\\"south_stand\\\", \\\"east_stand\\\", \\\"west_stand\\\", \\\"vip_lounge\\\"],\n","    \\\"weather_alert\\\": [\\\"pitch\\\", \\\"north_stand\\\", \\\"south_stand\\\"],\n","    \\\"power_spike\\\": [\\\"concourse_north\\\", \\\"vip_lounge\\\", \\\"medical_bay_1\\\"],\n","    \\\"security_breach\\\": [\\\"gate_a\\\", \\\"gate_b\\\", \\\"vip_lounge\\\", \\\"parking_lot_a\\\"],\n","    \\\"transport_delay\\\": [\\\"parking_lot_a\\\", \\\"parking_lot_b\\\"],\n","    \\\"food_shortage\\\": [\\\"concourse_north\\\", \\\"concourse_south\\\"],\n","    \\\"ticket_fraud\\\": [\\\"gate_a\\\", \\\"gate_b\\\", \\\"gate_c\\\", \\\"gate_d\\\"],\n","    \\\"cctv_anomaly\\\": STADIUM_ZONES,\n","}\n","\n","# in-memory current sim state keyed by match_id\n","SIM_STATE: Dict[str, Dict[str, Any]] = {}\n","\n","\n","def _base_state(match_id: str, capacity: int) -> Dict[str, Any]:\n","    return {\n","        \\\"match_id\\\": match_id,\n","        \\\"start_ts\\\": datetime.now(timezone.utc),\n","        \\\"capacity\\\": capacity,\n","        \\\"crowd_movement\\\": 4200,\n","        \\\"weather_temp\\\": 24.0,\n","        \\\"weather_wind\\\": 12.0,\n","        \\\"weather_condition\\\": \\\"Clear\\\",\n","        \\\"ticket_validation\\\": 62000,\n","        \\\"parking_occupied\\\": 8200,\n","        \\\"parking_capacity\\\": 10000,\n","        \\\"security_score\\\": 92,\n","        \\\"cctv_alerts\\\": 0,\n","        \\\"medical_active\\\": 1,\n","        \\\"energy_load_kw\\\": 6800,\n","        \\\"food_stock_pct\\\": 88,\n","        \\\"transport_delay_min\\\": 2,\n","        \\\"stadium_capacity_pct\\\": 78,\n","        \\\"match_minute\\\": 0,\n","        \\\"active_events\\\": [],  # list of dicts: {event_type, zone, severity, ttl}\n","        \\\"history\\\": [],  # list of last N telemetry snapshots\n","    }\n","\n","\n","def _step_sim(state: Dict[str, Any]) -> Dict[str, Any]:\n","    # organic noise\n","    def wobble(v, lo, hi, delta):\n","        v += random.uniform(-delta, delta)\n","        return max(lo, min(hi, v))\n","\n","    state[\\\"crowd_movement\\\"] = int(wobble(state[\\\"crowd_movement\\\"], 1000, 12000, 250))\n","    state[\\\"weather_temp\\\"] = round(wobble(state[\\\"weather_temp\\\"], 5, 40, 0.4), 1)\n","    state[\\\"weather_wind\\\"] = round(wobble(state[\\\"weather_wind\\\"], 0, 90, 1.2), 1)\n","    state[\\\"ticket_validation\\\"] = min(state[\\\"capacity\\\"], state[\\\"ticket_validation\\\"] + random.randint(0, 40))\n","    state[\\\"parking_occupied\\\"] = min(state[\\\"parking_capacity\\\"], state[\\\"parking_occupied\\\"] + random.randint(-5, 25))\n","    state[\\\"security_score\\\"] = int(wobble(state[\\\"security_score\\\"], 0, 100, 1.5))\n","    state[\\\"cctv_alerts\\\"] = max(0, state[\\\"cctv_alerts\\\"] + random.choice([-1, 0, 0, 0, 1]))\n","    state[\\\"medical_active\\\"] = max(0, state[\\\"medical_active\\\"] + random.choice([-1, 0, 0, 0]))\n","    state[\\\"energy_load_kw\\\"] = int(wobble(state[\\\"energy_load_kw\\\"], 3000, 15000, 120))\n","    state[\\\"food_stock_pct\\\"] = int(wobble(state[\\\"food_stock_pct\\\"], 0, 100, 1.0))\n","    state[\\\"transport_delay_min\\\"] = max(0, state[\\\"transport_delay_min\\\"] + random.choice([-1, 0, 0, 1]))\n","    state[\\\"stadium_capacity_pct\\\"] = min(100, int(state[\\\"ticket_validation\\\"] / max(1, state[\\\"capacity\\\"]) * 100))\n","    elapsed = (datetime.now(timezone.utc) - state[\\\"start_ts\\\"]).total_seconds() / 60\n","    state[\\\"match_minute\\\"] = min(120, int(elapsed))\n","\n","    # apply active event effects\n","    remaining = []\n","    for ev in state[\\\"active_events\\\"]:\n","        sev = ev[\\\"severity\\\"]\n","        weight = {\\\"low\\\": 1, \\\"medium\\\": 2, \\\"high\\\": 3, \\\"critical\\\": 5}[sev]\n","        et = ev[\\\"event_type\\\"]\n","        if et == \\\"crowd_surge\\\":\n","            state[\\\"crowd_movement\\\"] = min(15000, state[\\\"crowd_movement\\\"] + 400 * weight)\n","            state[\\\"security_score\\\"] = max(0, state[\\\"security_score\\\"] - 3 * weight)\n","        elif et == \\\"medical_emergency\\\":\n","            state[\\\"medical_active\\\"] += weight\n","        elif et == \\\"weather_alert\\\":\n","            state[\\\"weather_wind\\\"] = min(120, state[\\\"weather_wind\\\"] + 4 * weight)\n","            state[\\\"weather_condition\\\"] = \\\"Storm\\\"\n","        elif et == \\\"power_spike\\\":\n","            state[\\\"energy_load_kw\\\"] = min(20000, state[\\\"energy_load_kw\\\"] + 800 * weight)\n","        elif et == \\\"security_breach\\\":\n","            state[\\\"security_score\\\"] = max(0, state[\\\"security_score\\\"] - 10 * weight)\n","            state[\\\"cctv_alerts\\\"] += weight\n","        elif et == \\\"transport_delay\\\":\n","            state[\\\"transport_delay_min\\\"] += 5 * weight\n","        elif et == \\\"food_shortage\\\":\n","            state[\\\"food_stock_pct\\\"] = max(0, state[\\\"food_stock_pct\\\"] - 8 * weight)\n","        elif et == \\\"ticket_fraud\\\":\n","            state[\\\"security_score\\\"] = max(0, state[\\\"security_score\\\"] - 2 * weight)\n","        elif et == \\\"cctv_anomaly\\\":\n","            state[\\\"cctv_alerts\\\"] += weight\n","        ev[\\\"ttl\\\"] -= 1\n","        if ev[\\\"ttl\\\"] > 0:\n","            remaining.append(ev)\n","    state[\\\"active_events\\\"] = remaining\n","\n","    snap = build_telemetry(state)\n","    state[\\\"history\\\"].append(snap.model_dump())\n","    state[\\\"history\\\"] = state[\\\"history\\\"][-60:]\n","    return state\n","\n","\n","def build_telemetry(state: Dict[str, Any]) -> Telemetry:\n","    return Telemetry(\n","        match_id=state[\\\"match_id\\\"],\n","        ts=now_iso(),\n","        crowd_movement=int(state[\\\"crowd_movement\\\"]),\n","        weather_temp=float(state[\\\"weather_temp\\\"]),\n","        weather_wind=float(state[\\\"weather_wind\\\"]),\n","        weather_condition=state[\\\"weather_condition\\\"],\n","        ticket_validation=int(state[\\\"ticket_validation\\\"]),\n","        parking_occupied=int(state[\\\"parking_occupied\\\"]),\n","        parking_capacity=int(state[\\\"parking_capacity\\\"]),\n","        security_score=int(state[\\\"security_score\\\"]),\n","        cctv_alerts=int(state[\\\"cctv_alerts\\\"]),\n","        medical_active=int(state[\\\"medical_active\\\"]),\n","        energy_load_kw=int(state[\\\"energy_load_kw\\\"]),\n","        food_stock_pct=int(state[\\\"food_stock_pct\\\"]),\n","        transport_delay_min=int(state[\\\"transport_delay_min\\\"]),\n","        stadium_capacity_pct=int(state[\\\"stadium_capacity_pct\\\"]),\n","        match_minute=int(state[\\\"match_minute\\\"]),\n","    )\n","\n","\n","# ---------- Match endpoints ----------\n","@api.get(\\\"/\\\")\n","async def root():\n","    return {\\\"service\\\": \\\"OmniArena Nexus\\\", \\\"status\\\": \\\"online\\\"}\n","\n","\n","@api.post(\\\"/match/start\\\", response_model=MatchConfig)\n","async def start_match(cfg: CreateMatch):\n","    m = MatchConfig(**cfg.model_dump())\n","    await db.matches.insert_one(m.model_dump())\n","    SIM_STATE[m.id] = _base_state(m.id, m.capacity)\n","    return m\n","\n","\n","@api.get(\\\"/match/current\\\", response_model=Optional[MatchConfig])\n","async def current_match():\n","    doc = await db.matches.find_one({}, sort=[(\\\"started_at\\\", -1)], projection={\\\"_id\\\": 0})\n","    if not doc:\n","        return None\n","    if doc[\\\"id\\\"] not in SIM_STATE:\n","        SIM_STATE[doc[\\\"id\\\"]] = _base_state(doc[\\\"id\\\"], doc.get(\\\"capacity\\\", 80000))\n","    return MatchConfig(**doc)\n","\n","\n","@api.patch(\\\"/match/{match_id}/settings\\\", response_model=MatchConfig)\n","async def patch_settings(match_id: str, patch: SettingsPatch):\n","    update = {k: v for k, v in patch.model_dump().items() if v is not None}\n","    if not update:\n","        raise HTTPException(400, \\\"no updates\\\")\n","    await db.matches.update_one({\\\"id\\\": match_id}, {\\\"$set\\\": update})\n","    doc = await db.matches.find_one({\\\"id\\\": match_id}, projection={\\\"_id\\\": 0})\n","    if not doc:\n","        raise HTTPException(404, \\\"match not found\\\")\n","    return MatchConfig(**doc)\n","\n","\n","# ---------- Telemetry ----------\n","@api.get(\\\"/telemetry/{match_id}\\\")\n","async def get_telemetry(match_id: str):\n","    if match_id not in SIM_STATE:\n","        doc = await db.matches.find_one({\\\"id\\\": match_id}, projection={\\\"_id\\\": 0})\n","        if not doc:\n","            raise HTTPException(404, \\\"match not found\\\")\n","        SIM_STATE[match_id] = _base_state(match_id, doc.get(\\\"capacity\\\", 80000))\n","    state = _step_sim(SIM_STATE[match_id])\n","    snap = build_telemetry(state)\n","    # persist snapshot occasionally for analytics\n","    if random.random() < 0.15:\n","        await db.telemetry.insert_one(snap.model_dump())\n","    return {\n","        \\\"telemetry\\\": snap.model_dump(),\n","        \\\"history\\\": state[\\\"history\\\"],\n","        \\\"active_events\\\": state[\\\"active_events\\\"],\n","    }\n","\n","\n","# ---------- Incidents ----------\n","@api.post(\\\"/incident/trigger\\\", response_model=Incident)\n","async def trigger_incident(req: TriggerReq):\n","    match = await db.matches.find_one({}, sort=[(\\\"started_at\\\", -1)], projection={\\\"_id\\\": 0})\n","    if not match:\n","        raise HTTPException(400, \\\"no active match\\\")\n","    zones = EVENT_ZONE_MAP.get(req.event_type, STADIUM_ZONES)\n","    zone = req.zone or random.choice(zones)\n","    severity = req.severity or random.choice([\\\"medium\\\", \\\"high\\\", \\\"critical\\\", \\\"high\\\"])\n","    incident = Incident(\n","        match_id=match[\\\"id\\\"],\n","        event_type=req.event_type,\n","        zone=zone,\n","        severity=severity,\n","        context={\\\"triggered_by\\\": \\\"manual\\\"},\n","    )\n","    await db.incidents.insert_one(incident.model_dump())\n","    # inject into sim\n","    state = SIM_STATE.get(match[\\\"id\\\"])\n","    if state is not None:\n","        ttl = {\\\"low\\\": 4, \\\"medium\\\": 6, \\\"high\\\": 9, \\\"critical\\\": 12}[severity]\n","        state[\\\"active_events\\\"].append({\n","            \\\"event_type\\\": req.event_type,\n","            \\\"zone\\\": zone,\n","            \\\"severity\\\": severity,\n","            \\\"ttl\\\": ttl,\n","            \\\"incident_id\\\": incident.id,\n","        })\n","    return incident\n","\n","\n","@api.get(\\\"/incidents\\\")\n","async def list_incidents(match_id: Optional[str] = None, limit: int = 50):\n","    q = {\\\"match_id\\\": match_id} if match_id else {}\n","    docs = await db.incidents.find(q, projection={\\\"_id\\\": 0}).sort(\\\"detected_at\\\", -1).to_list(limit)\n","    return docs\n","\n","\n","@api.get(\\\"/incident/{incident_id}\\\")\n","async def get_incident(incident_id: str):\n","    doc = await db.incidents.find_one({\\\"id\\\": incident_id}, projection={\\\"_id\\\": 0})\n","    if not doc:\n","        raise HTTPException(404, \\\"not found\\\")\n","    return doc\n","\n","\n","@api.post(\\\"/incident/{incident_id}/accept\\\")\n","async def accept_plan(incident_id: str):\n","    doc = await db.incidents.find_one({\\\"id\\\": incident_id}, projection={\\\"_id\\\": 0})\n","    if not doc:\n","        raise HTTPException(404, \\\"not found\\\")\n","    resolved_at = now_iso()\n","    detected = datetime.fromisoformat(doc[\\\"detected_at\\\"])\n","    seconds = int((datetime.now(timezone.utc) - detected).total_seconds())\n","    await db.incidents.update_one(\n","        {\\\"id\\\": incident_id},\n","        {\\\"$set\\\": {\\\"status\\\": \\\"resolved\\\", \\\"resolved_at\\\": resolved_at, \\\"resolution_seconds\\\": seconds}},\n","    )\n","    # remove from active sim events\n","    state = SIM_STATE.get(doc[\\\"match_id\\\"])\n","    if state:\n","        state[\\\"active_events\\\"] = [e for e in state[\\\"active_events\\\"] if e.get(\\\"incident_id\\\") != incident_id]\n","    return {\\\"ok\\\": True, \\\"resolution_seconds\\\": seconds}\n","\n","\n","# ---------- LLM Director ----------\n","SYSTEM_PROMPT = \\\"\\\"\\\"You are the AI DIRECTOR for OmniArena Nexus, an autonomous ops-center overseeing a FIFA World Cup 2026 stadium.\n","You receive live telemetry and an active incident. You MUST produce a decision as STRICT VALID JSON only.\n","\n","Schema (all fields required):\n","{\n","  \\\"situation\\\": string,               // 2-3 sentence factual assessment\n","  \\\"risk_score\\\": number,              // 0-100\n","  \\\"priority\\\": \\\"LOW\\\"|\\\"MEDIUM\\\"|\\\"HIGH\\\"|\\\"CRITICAL\\\",\n","  \\\"affected_areas\\\": string[],        // stadium zones or systems\n","  \\\"immediate_actions\\\": string[],     // 3-6 concrete steps in first 5 minutes\n","  \\\"long_term_actions\\\": string[],     // 2-4 follow-up steps\n","  \\\"reasoning\\\": string,               // why this plan works\n","  \\\"expected_improvement\\\": string,    // measurable outcome forecast\n","  \\\"executive_summary\\\": string        // 1-2 sentence briefing for the director\n","}\n","Rules:\n","- Output ONLY the JSON object. No markdown, no backticks, no prose.\n","- Base numbers on the telemetry supplied.\n","- Be decisive and specific to the zone and event type.\n","\\\"\\\"\\\"\n","\n","MODEL_CATALOG = {\n","    \\\"openai/gpt-5.2\\\": (\\\"openai\\\", \\\"gpt-5.2\\\"),\n","    \\\"anthropic/claude-sonnet-4-5\\\": (\\\"anthropic\\\", \\\"claude-sonnet-4-5-20250929\\\"),\n","    \\\"gemini/gemini-3-flash\\\": (\\\"gemini\\\", \\\"gemini-3-flash-preview\\\"),\n","}\n","\n","\n","def _build_prompt(incident: dict, telemetry: dict) -> str:\n","    return (\n","        \\\"INCIDENT:\\n\\\" + json.dumps(incident, default=str) +\n","        \\\"\\n\\nCURRENT_TELEMETRY:\\n\\\" + json.dumps(telemetry, default=str) +\n","        \\\"\\n\\nProduce the JSON decision object now.\\\"\n","    )\n","\n","\n","async def _stream_llm(model_key: str, prompt: str):\n","    from emergentintegrations.llm.chat import LlmChat, UserMessage, TextDelta, StreamDone\n","    provider, model = MODEL_CATALOG.get(model_key, MODEL_CATALOG[\\\"openai/gpt-5.2\\\"])\n","    session_id = str(uuid.uuid4())\n","    chat = LlmChat(\n","        api_key=EMERGENT_LLM_KEY,\n","        session_id=session_id,\n","        system_message=SYSTEM_PROMPT,\n","    ).with_model(provider, model)\n","    msg = UserMessage(text=prompt)\n","    async for ev in chat.stream_message(msg):\n","        if isinstance(ev, TextDelta):\n","            yield ev.content\n","        elif isinstance(ev, StreamDone):\n","            break\n","\n","\n","def _extract_json(text: str) -> Optional[dict]:\n","    text = text.strip()\n","    # strip fences if any\n","    if text.startswith(\\\"```\\\"):\n","        text = text.strip(\\\"`\\\")\n","        if text.lower().startswith(\\\"json\\\"):\n","            text = text[4:]\n","    # find first { and last }\n","    start = text.find(\\\"{\\\")\n","    end = text.rfind(\\\"}\\\")\n","    if start == -1 or end == -1:\n","        return None\n","    try:\n","        return json.loads(text[start:end + 1])\n","    except json.JSONDecodeError:\n","        return None\n","\n","\n","@api.post(\\\"/director/decide/stream\\\")\n","async def decide_stream(req: DecideReq):\n","    incident = await db.incidents.find_one({\\\"id\\\": req.incident_id}, projection={\\\"_id\\\": 0})\n","    if not incident:\n","        raise HTTPException(404, \\\"incident not found\\\")\n","    state = SIM_STATE.get(incident[\\\"match_id\\\"])\n","    telemetry = build_telemetry(state).model_dump() if state else {}\n","    match = await db.matches.find_one({\\\"id\\\": incident[\\\"match_id\\\"]}, projection={\\\"_id\\\": 0})\n","    model_key = req.model or (match.get(\\\"active_model\\\") if match else None) or \\\"openai/gpt-5.2\\\"\n","    prompt = _build_prompt(incident, telemetry)\n","\n","    async def gen():\n","        buffer = []\n","        try:\n","            async for chunk in _stream_llm(model_key, prompt):\n","                buffer.append(chunk)\n","                yield f\\\"data: {json.dumps({'type':'delta','text':chunk})}\\n\\n\\\"\n","            full = \\\"\\\".join(buffer)\n","            decision = _extract_json(full) or {}\n","            record = {\n","                \\\"id\\\": str(uuid.uuid4()),\n","                \\\"incident_id\\\": req.incident_id,\n","                \\\"match_id\\\": incident[\\\"match_id\\\"],\n","                \\\"model\\\": model_key,\n","                \\\"raw\\\": full,\n","                \\\"decision\\\": decision,\n","                \\\"created_at\\\": now_iso(),\n","            }\n","            await db.decisions.insert_one(record)\n","            payload = {\\\"type\\\": \\\"done\\\", \\\"decision\\\": decision, \\\"model\\\": model_key, \\\"decision_id\\\": record[\\\"id\\\"]}\n","            yield f\\\"data: {json.dumps(payload)}\\n\\n\\\"\n","        except Exception as e:\n","            log.exception(\\\"stream error\\\")\n","            yield f\\\"data: {json.dumps({'type':'error','error':str(e)})}\\n\\n\\\"\n","\n","    return StreamingResponse(\n","        gen(),\n","        media_type=\\\"text/event-stream\\\",\n","        headers={\\\"Cache-Control\\\": \\\"no-cache\\\", \\\"X-Accel-Buffering\\\": \\\"no\\\", \\\"Connection\\\": \\\"keep-alive\\\"},\n","    )\n","\n","\n","@api.post(\\\"/director/compare\\\")\n","async def compare_llms(req: CompareReq):\n","    incident = await db.incidents.find_one({\\\"id\\\": req.incident_id}, projection={\\\"_id\\\": 0})\n","    if not incident:\n","        raise HTTPException(404, \\\"incident not found\\\")\n","    state = SIM_STATE.get(incident[\\\"match_id\\\"])\n","    telemetry = build_telemetry(state).model_dump() if state else {}\n","    prompt = _build_prompt(incident, telemetry)\n","\n","    async def run_one(model_key: str):\n","        buf = []\n","        try:\n","            async for chunk in _stream_llm(model_key, prompt):\n","                buf.append(chunk)\n","            full = \\\"\\\".join(buf)\n","            return {\\\"model\\\": model_key, \\\"decision\\\": _extract_json(full), \\\"raw\\\": full}\n","        except Exception as e:\n","            return {\\\"model\\\": model_key, \\\"decision\\\": None, \\\"raw\\\": \\\"\\\", \\\"error\\\": str(e)}\n","\n","    results = await asyncio.gather(*[run_one(m) for m in MODEL_CATALOG.keys()])\n","    # persist\n","    for r in results:\n","        await db.decisions.insert_one({\n","            \\\"id\\\": str(uuid.uuid4()),\n","            \\\"incident_id\\\": req.incident_id,\n","            \\\"match_id\\\": incident[\\\"match_id\\\"],\n","            \\\"model\\\": r[\\\"model\\\"],\n","            \\\"raw\\\": r.get(\\\"raw\\\", \\\"\\\"),\n","            \\\"decision\\\": r.get(\\\"decision\\\"),\n","            \\\"created_at\\\": now_iso(),\n","            \\\"comparison\\\": True,\n","        })\n","    return {\\\"incident_id\\\": req.incident_id, \\\"results\\\": results}\n","\n","\n","# ---------- Analytics ----------\n","@api.get(\\\"/analytics/summary\\\")\n","async def analytics_summary(match_id: Optional[str] = None):\n","    q = {\\\"match_id\\\": match_id} if match_id else {}\n","    incidents = await db.incidents.find(q, projection={\\\"_id\\\": 0}).sort(\\\"detected_at\\\", -1).to_list(200)\n","    total = len(incidents)\n","    resolved = [i for i in incidents if i.get(\\\"status\\\") == \\\"resolved\\\"]\n","    avg_res = int(sum((i.get(\\\"resolution_seconds\\\") or 0) for i in resolved) / len(resolved)) if resolved else 0\n","    by_type: Dict[str, int] = {}\n","    by_severity: Dict[str, int] = {}\n","    for i in incidents:\n","        by_type[i[\\\"event_type\\\"]] = by_type.get(i[\\\"event_type\\\"], 0) + 1\n","        by_severity[i[\\\"severity\\\"]] = by_severity.get(i[\\\"severity\\\"], 0) + 1\n","    # risk trend from last decisions\n","    decisions = await db.decisions.find(q, projection={\\\"_id\\\": 0}).sort(\\\"created_at\\\", -1).to_list(50)\n","    trend = []\n","    for d in reversed(decisions):\n","        dec = d.get(\\\"decision\\\") or {}\n","        if isinstance(dec, dict) and \\\"risk_score\\\" in dec:\n","            trend.append({\\\"ts\\\": d.get(\\\"created_at\\\"), \\\"risk_score\\\": dec.get(\\\"risk_score\\\"), \\\"model\\\": d.get(\\\"model\\\")})\n","    return {\n","        \\\"total_incidents\\\": total,\n","        \\\"resolved\\\": len(resolved),\n","        \\\"open\\\": total - len(resolved),\n","        \\\"avg_resolution_seconds\\\": avg_res,\n","        \\\"by_type\\\": by_type,\n","        \\\"by_severity\\\": by_severity,\n","        \\\"risk_trend\\\": trend,\n","        \\\"recent_incidents\\\": incidents[:20],\n","    }\n","\n","\n","@api.get(\\\"/decisions\\\")\n","async def list_decisions(incident_id: Optional[str] = None, limit: int = 30):\n","    q = {\\\"incident_id\\\": incident_id} if incident_id else {}\n","    docs = await db.decisions.find(q, projection={\\\"_id\\\": 0}).sort(\\\"created_at\\\", -1).to_list(limit)\n","    return docs\n","\n","\n","# ---------- Mount ----------\n","app.include_router(api)\n","app.add_middleware(\n","    CORSMiddleware,\n","    allow_credentials=True,\n","    allow_origins=os.environ.get(\\\"CORS_ORIGINS\\\", \\\"*\\\").split(\\\",\\\"),\n","    allow_methods=[\\\"*\\\"],\n","    allow_headers=[\\\"*\\\"],\n",")\n","\n","\n","@app.on_event(\\\"shutdown\\\")\n","async def _shutdown():\n","    client.close()\n","\"\n","Observation: Overwrite successful: /app/backend/server.py"],"metadata":{"id":"YZc7tkg-Cypd"},"execution_count":null,"outputs":[]},{"cell_type":"code","execution_count":null,"metadata":{"id":"d_UM4jHBCt5E"},"outputs":[],"source":["\n","Action: file_editor create /app/frontend/src/index.css --file-text \"@import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@300;400;500;600;700&family=IBM+Plex+Sans:wght@300;400;500;600&display=swap');\n","\n","@tailwind base;\n","@tailwind components;\n","@tailwind utilities;\n","\n",":root {\n","    --nexus-bg: #050505;\n","    --nexus-panel: #0A0A0A;\n","    --nexus-elev: #111114;\n","    --nexus-border: rgba(255, 255, 255, 0.08);\n","    --nexus-border-strong: rgba(255, 255, 255, 0.15);\n","    --nexus-cyan: #00E5FF;\n","    --nexus-amber: #FFB300;\n","    --nexus-red: #FF1744;\n","    --nexus-text: #FFFFFF;\n","    --nexus-text-2: #A0A0AB;\n","    --nexus-text-3: #52525B;\n","}\n","\n","html, body, #root {\n","    background: var(--nexus-bg);\n","    color: var(--nexus-text);\n","}\n","\n","body {\n","    margin: 0;\n","    font-family: 'IBM Plex Sans', system-ui, sans-serif;\n","    -webkit-font-smoothing: antialiased;\n","    -moz-osx-font-smoothing: grayscale;\n","    background: var(--nexus-bg);\n","    background-image:\n","      radial-gradient(circle at 15% 10%, rgba(0, 229, 255, 0.04), transparent 40%),\n","      radial-gradient(circle at 85% 90%, rgba(255, 179, 0, 0.03), transparent 45%);\n","}\n","\n",".font-mono, code, pre {\n","    font-family: 'JetBrains Mono', ui-monospace, Menlo, monospace;\n","}\n","\n","@layer base {\n","    :root {\n","        --background: 0 0% 2%;\n","        --foreground: 0 0% 98%;\n","        --card: 0 0% 4%;\n","        --card-foreground: 0 0% 98%;\n","        --popover: 0 0% 6%;\n","        --popover-foreground: 0 0% 98%;\n","        --primary: 187 100% 50%;\n","        --primary-foreground: 0 0% 4%;\n","        --secondary: 0 0% 12%;\n","        --secondary-foreground: 0 0% 98%;\n","        --muted: 0 0% 10%;\n","        --muted-foreground: 0 0% 63%;\n","        --accent: 187 100% 50%;\n","        --accent-foreground: 0 0% 4%;\n","        --destructive: 350 100% 55%;\n","        --destructive-foreground: 0 0% 98%;\n","        --border: 0 0% 14%;\n","        --input: 0 0% 12%;\n","        --ring: 187 100% 50%;\n","        --radius: 0.125rem;\n","    }\n","    * {\n","        @apply border-border;\n","    }\n","    body {\n","        @apply bg-background text-foreground;\n","    }\n","}\n","\n",".nexus-scanline::after {\n","    content: '';\n","    position: absolute; inset: 0;\n","    pointer-events: none;\n","    background: repeating-linear-gradient(0deg, rgba(255,255,255,0.02) 0px, rgba(255,255,255,0.02) 1px, transparent 1px, transparent 3px);\n","    mix-blend-mode: overlay;\n","}\n","\n",".tile-grid {\n","    background: var(--nexus-border);\n","}\n",".tile-grid > * {\n","    background: var(--nexus-panel);\n","}\n","\n",".blink-cursor::after {\n","    content: '▌';\n","    color: var(--nexus-cyan);\n","    margin-left: 2px;\n","    animation: blink 1s steps(2) infinite;\n","}\n","@keyframes blink { 50% { opacity: 0 } }\n","\n",".pulse-red {\n","    animation: pulseRed 1.4s ease-in-out infinite;\n","    box-shadow: 0 0 0 0 rgba(255, 23, 68, 0.5);\n","}\n","@keyframes pulseRed {\n","    0%, 100% { box-shadow: inset 0 0 0 1px rgba(255,23,68,0.6), 0 0 20px rgba(255,23,68,0.2); }\n","    50% { box-shadow: inset 0 0 0 1px rgba(255,23,68,1), 0 0 30px rgba(255,23,68,0.55); }\n","}\n","\n",".pulse-amber {\n","    animation: pulseAmber 1.8s ease-in-out infinite;\n","}\n","@keyframes pulseAmber {\n","    0%, 100% { box-shadow: inset 0 0 0 1px rgba(255,179,0,0.5); }\n","    50% { box-shadow: inset 0 0 0 1px rgba(255,179,0,0.9), 0 0 22px rgba(255,179,0,0.35); }\n","}\n","\n",".ping-dot {\n","    position: absolute;\n","    width: 14px; height: 14px; border-radius: 999px;\n","}\n",".ping-dot::before {\n","    content:''; position:absolute; inset:0; border-radius:999px; background: inherit;\n","    animation: pingR 1.6s cubic-bezier(0,0,0.2,1) infinite;\n","}\n","@keyframes pingR {\n","    75%, 100% { transform: scale(2.6); opacity: 0; }\n","}\n","\n",".hud-grid-bg {\n","    background-image:\n","      linear-gradient(rgba(255,255,255,0.03) 1px, transparent 1px),\n","      linear-gradient(90deg, rgba(255,255,255,0.03) 1px, transparent 1px);\n","    background-size: 32px 32px;\n","}\n","\n","/* json viewer */\n",".json-key { color: var(--nexus-cyan); }\n",".json-string { color: var(--nexus-amber); }\n",".json-number { color: #C5F547; }\n",".json-bool { color: #FF66C4; }\n",".json-null { color: var(--nexus-text-3); }\n","\n","::selection { background: rgba(0, 229, 255, 0.35); color: #fff; }\n","\n",".uppercase-track { letter-spacing: 0.14em; }\n","\"\n","Observation: Overwrite successful: /app/frontend/src/index.css"]},{"cell_type":"code","source":["\n","Action: file_editor create /app/frontend/src/App.css --file-text \".App { min-height: 100vh; background: var(--nexus-bg); }\n","\"\n","Observation: Overwrite successful: /app/frontend/src/App.css"],"metadata":{"id":"y5aeDoCCC5vN"},"execution_count":null,"outputs":[]}]}